#include <stdio.h>
#include <stdbool.h>

bool isPrime(int n) {
    if (n <= 1) return false;
    if (n == 2) return true;
    if (n % 2 == 0) return false;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return false;
    }
    return true;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C;
        scanf("%d %d", &R, &C);
        char grid[R][C];
        for (int i = 0; i < R; i++) {
            scanf("%s", grid[i]);
        }
        int count = 0;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (grid[i][j] == '^') {
                    int L = 0, R = 0, T = 0, B = 0;
                    for (int k = j - 1; k >= 0; k--) {
                        if (grid[i][k] == '^') L++;
                        else break;
                    }
                    for (int k = j + 1; k < C; k++) {
                        if (grid[i][k] == '^') R++;
                        else break;
                    }
                    for (int k = i - 1; k >= 0; k--) {
                        if (grid[k][j] == '^') T++;
                        else break;
                    }
                    for (int k = i + 1; k < R; k++) {
                        if (grid[k][j] == '^') B++;
                        else break;
                    }
                    int min = L;
                    if (R < min) min = R;
                    if (T < min) min = T;
                    if (B < min) min = B;
                    for (int k = 2; k <= min; k++) {
                        if (isPrime(k)) {
                            count++;
                            break;
                        }
                    }
                }
            }
        }
        if (count % 2 == 0) printf("Kirito\n");
        else printf("Asuna\n");
    }
    return 0;
}

