def is_prime(n):
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

T = int(input())
for _ in range(T):
    R, C = map(int, input().split())
    grid = [list(input()) for _ in range(R)]
    count = 0
    for i in range(R):
        for j in range(C):
            if grid[i][j] == '^':
                L = 0
                for k in range(j - 1, -1, -1):
                    if grid[i][k] == '^':
                        L += 1
                    else:
                        break
                R = 0
                for k in range(j + 1, C):
                    if grid[i][k] == '^':
                        R += 1
                    else:
                        break
                T = 0
                for k in range(i - 1, -1, -1):
                    if grid[k][j] == '^':
                        T += 1
                    else:
                        break
                B = 0
                for k in range(i + 1, R):
                    if grid[k][j] == '^':
                        B += 1
                    else:
                        break
                min_val = min(L, R, T, B)
                for k in range(2, min_val + 1):
                    if is_prime(k):
                        count += 1
                        break
